// src/Login.js
import React, { useState } from 'react';
import axios from 'axios';

function Login({ onLogin }) {
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [mensagem, setMensagem] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/login', { usuario, senha });
      onLogin(res.data);
    } catch (error) {
      setMensagem('Usuário ou senha inválidos!');
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Painel esquerdo: só desktop */}
      <div
        className="hidden md:flex w-1/2 bg-gradient-to-br from-[#3172C0] to-[#1D3557] items-center justify-center p-8"
      >
        {/* Coloque aqui sua imagem ou ilustração */}
        <img
          src="/assets/login-illustration.svg"
          alt="Illustration"
          className="max-w-xs"
        />
      </div>

      {/* Formulário */}
      <div className="flex flex-1 items-center justify-center p-6 bg-gray-50">
        <div className="w-full max-w-md bg-white rounded-2xl shadow-lg p-8 space-y-6">
          <h1 className="text-3xl font-bold text-center text-[#152A3F]">
            PoliUB Atendimentos
          </h1>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">
                Usuário
              </label>
              <input
                type="text"
                placeholder="Digite seu usuário"
                value={usuario}
                onChange={e => setUsuario(e.target.value)}
                required
                className="mt-1 w-full px-4 py-2 border rounded-full focus:outline-none focus:ring-2 focus:ring-[#3172C0]"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">
                Senha
              </label>
              <input
                type="password"
                placeholder="••••••••"
                value={senha}
                onChange={e => setSenha(e.target.value)}
                required
                className="mt-1 w-full px-4 py-2 border rounded-full focus:outline-none focus:ring-2 focus:ring-[#3172C0]"
              />
            </div>
            <button
              type="submit"
              className="w-full bg-[#3172C0] hover:bg-[#1D3557] text-white py-2 rounded-full font-semibold transition"
            >
              Entrar
            </button>
          </form>
          {mensagem && (
            <p className="text-center text-red-600 mt-2">{mensagem}</p>
          )}
        </div>
      </div>
    </div>
  );
}

export default Login;
